{"type": "post", "post": {"team": "customer_support", "channel": "provider_queries", "user": "John Smith", "message": "I've noticed an increase in queries related to password resets. Should we consider a tutorial or FAQ section on the platform to assist users with this?", "created_at": 1620505000000}}
